# Huber loss
def huber(y, y_hat, delta=1.0):
    r = np.abs(y - y_hat)
    return np.where(r <= delta, 0.5 * r**2, delta * r - 0.5 * delta**2).mean()

print(f"Huber good={huber(y,y_good):.4f}  bad={huber(y,y_bad):.4f}")

import torch
import torch.nn as nn

class ConvBlock(nn.Module):
    def __init__(self, in_ch, out_ch, stride=1):
        super().__init__()
        self.conv = nn.Conv2d(in_ch, out_ch, 3, stride=stride, padding=1, bias=False)
        self.bn   = nn.BatchNorm2d(out_ch)
    def forward(self, x): return torch.relu(self.bn(self.conv(x)))

class ResBlock(nn.Module):
    def __init__(self, ch):
        super().__init__()
        self.b1 = ConvBlock(ch, ch)
        self.b2 = ConvBlock(ch, ch)
    def forward(self, x): return x + self.b2(self.b1(x))  # skip connection

class SmallResNet(nn.Module):
    def __init__(self, num_classes=10):
        super().__init__()
        self.stem = ConvBlock(3, 32, stride=1)
        self.res  = nn.Sequential(ResBlock(32), ConvBlock(32,64,stride=2), ResBlock(64))
        self.pool = nn.AdaptiveAvgPool2d(1)
        self.fc   = nn.Linear(64, num_classes)
    def forward(self, x):
        return self.fc(self.pool(self.res(self.stem(x))).flatten(1))

model = SmallResNet()
x = torch.randn(4, 3, 32, 32)  # 4 images, 3 channels, 32x32
print("output shape:", model(x).shape)
params = sum(p.numel() for p in model.parameters())
print(f"parameters: {params:,}")

