import random

class QNetwork(nn.Module):
    def __init__(self, state_dim, n_actions):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(state_dim, 128), nn.ReLU(),
            nn.Linear(128, 128),       nn.ReLU(),
            nn.Linear(128, n_actions)
        )
    def forward(self, x): return self.net(x)

class ReplayBuffer:
    def __init__(self, capacity=10000):
        self.buf = deque(maxlen=capacity)
    def push(self, *args): self.buf.append(tuple(args))
    def sample(self, n):   return random.sample(self.buf, n)
    def __len__(self):     return len(self.buf)

# DQN update step
def dqn_update(online, target, buf, opt, gamma=0.99, batch=64):
    if len(buf) < batch: return
    batch_data = buf.sample(batch)
    s,a,r,ns,done = [torch.tensor(np.array(x), dtype=torch.float32)
                     for x in zip(*batch_data)]
    q_pred   = online(s).gather(1, a.long().unsqueeze(1)).squeeze()
    with torch.no_grad():
        q_next = target(ns).max(1).values
        q_target = r + gamma * q_next * (1-done)
    loss = nn.MSELoss()(q_pred, q_target)
    opt.zero_grad(); loss.backward(); opt.step()
    return loss.item()

online = QNetwork(4, 2); target = QNetwork(4, 2)
target.load_state_dict(online.state_dict())
print("DQN online/target networks ready.")

import numpy as np

class MultiArmedBandit:
    def __init__(self, k=5, seed=42):
        rng = np.random.default_rng(seed)
        self.means = rng.normal(0, 1, k)
        self.k     = k
    def pull(self, arm):
        return np.random.normal(self.means[arm], 1.0)

class EpsilonGreedy:
    def __init__(self, k, eps=0.1):
        self.Q, self.N, self.eps = np.zeros(k), np.zeros(k), eps
    def select(self):
        return np.random.randint(self.k) if np.random.rand()<self.eps else np.argmax(self.Q)
    def update(self, a, r):
        self.N[a] += 1; self.Q[a] += (r - self.Q[a]) / self.N[a]

np.random.seed(0)
env     = MultiArmedBandit(k=5)
agent   = EpsilonGreedy(k=5, eps=0.1)
total_r = 0.0

for t in range(1000):
    a      = agent.select()
    r      = env.pull(a)
    agent.update(a, r)
    total_r += r

print("True means:", env.means.round(3))
print("Estimated: ", agent.Q.round(3))
print(f"Best arm: {np.argmax(env.means)}  Agent mostly chose: {np.argmax(agent.N)}")
print(f"Total reward: {total_r:.1f}  Optimal: {np.max(env.means)*1000:.1f}")

import numpy as np
import matplotlib
matplotlib.use("Agg")

class Bandit:
    def __init__(self, k=10): self.means = np.random.randn(k); self.k=k
    def pull(self, a):        return np.random.randn() + self.means[a]

def run(k=10, steps=2000, eps_schedule="fixed", eps=0.1):
    env = Bandit(k)
    Q   = np.zeros(k); N = np.zeros(k)
    rewards = []
    for t in range(1, steps+1):
        if   eps_schedule == "fixed":  e = eps
        elif eps_schedule == "linear": e = max(0.01, 1.0 - t/steps)
        elif eps_schedule == "exp":    e = max(0.01, eps * 0.999**t)
        a = np.random.randint(k) if np.random.rand()<e else np.argmax(Q)
        r = env.pull(a)
        N[a]+=1; Q[a]+=(r-Q[a])/N[a]
        rewards.append(r)
    return np.mean(rewards[-100:])

np.random.seed(42)
for sched in ["fixed", "linear", "exp"]:
    avg = np.mean([run(eps_schedule=sched) for _ in range(20)])
    print(f"{sched:6s}  avg_reward_last100={avg:.3f}")

import torch
import torch.nn as nn
import torch.nn.functional as F

class Tower(nn.Module):
    def __init__(self, input_dim, hidden, embed_dim):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(input_dim, hidden), nn.ReLU(),
            nn.Linear(hidden, hidden),    nn.ReLU(),
            nn.Linear(hidden, embed_dim)
        )
    def forward(self, x): return F.normalize(self.net(x), dim=-1)

class TwoTower(nn.Module):
    def __init__(self, user_dim, item_dim, embed_dim=64):
        super().__init__()
        self.user_tower = Tower(user_dim, 128, embed_dim)
        self.item_tower = Tower(item_dim, 128, embed_dim)
    def forward(self, users, items):
        return self.user_tower(users), self.item_tower(items)

def in_batch_loss(u_emb, i_emb, temperature=0.07):
    logits = (u_emb @ i_emb.T) / temperature
    labels = torch.arange(len(u_emb))
    return F.cross_entropy(logits, labels)

torch.manual_seed(0)
model    = TwoTower(user_dim=32, item_dim=24, embed_dim=64)
opt      = torch.optim.Adam(model.parameters(), lr=1e-3)
for step in range(100):
    users = torch.randn(64, 32)
    items = torch.randn(64, 24)
    u_emb, i_emb = model(users, items)
    loss  = in_batch_loss(u_emb, i_emb)
    opt.zero_grad(); loss.backward(); opt.step()
    if step % 25 == 0: print(f"step {step:3d}  loss={loss.item():.4f}")

