import torch
import torch.nn as nn
import math

class RMSNorm(nn.Module):
    def __init__(self, dim, eps=1e-6):
        super().__init__()
        self.weight = nn.Parameter(torch.ones(dim))
        self.eps = eps
    def forward(self, x):
        rms = x.pow(2).mean(-1, keepdim=True).add(self.eps).sqrt()
        return self.weight * x / rms

class SwiGLU(nn.Module):
    def __init__(self, dim, hidden):
        super().__init__()
        self.w1 = nn.Linear(dim, hidden, bias=False)
        self.w2 = nn.Linear(hidden, dim, bias=False)
        self.w3 = nn.Linear(dim, hidden, bias=False)
    def forward(self, x):
        return self.w2(nn.functional.silu(self.w1(x)) * self.w3(x))

class DecoderBlock(nn.Module):
    def __init__(self, dim, n_heads, ffn_hidden):
        super().__init__()
        self.norm1 = RMSNorm(dim)
        self.attn  = nn.MultiheadAttention(dim, n_heads, batch_first=True)
        self.norm2 = RMSNorm(dim)
        self.ffn   = SwiGLU(dim, ffn_hidden)
    def forward(self, x):
        a, _ = self.attn(self.norm1(x), self.norm1(x), self.norm1(x),
                         is_causal=True)
        x = x + a
        return x + self.ffn(self.norm2(x))

block = DecoderBlock(dim=256, n_heads=8, ffn_hidden=512)
x = torch.randn(2, 10, 256)
print(block(x).shape)  # (2, 10, 256)

import numpy as np

# Reciprocal Rank Fusion — combine dense + sparse retrieval
def rrf(rankings: list[list[int]], k: int = 60) -> list[int]:
    """rankings: list of doc-id lists, each sorted by relevance."""
    scores: dict[int, float] = {}
    for ranking in rankings:
        for rank, doc_id in enumerate(ranking):
            scores[doc_id] = scores.get(doc_id, 0) + 1 / (k + rank + 1)
    return sorted(scores, key=scores.get, reverse=True)

# Example: dense and sparse return different orderings
dense_results  = [3, 1, 5, 2, 8]   # by embedding similarity
sparse_results = [1, 3, 7, 4, 5]   # by BM25 keyword score
fused = rrf([dense_results, sparse_results])
print("Dense: ", dense_results)
print("Sparse:", sparse_results)
print("RRF:   ", fused[:5])

# Semantic chunking stub
def semantic_chunk(text: str, max_tokens: int = 200) -> list[str]:
    sentences = text.replace("?", ".").replace("!", ".").split(".")
    chunks, current, count = [], [], 0
    for s in sentences:
        words = len(s.split())
        if count + words > max_tokens and current:
            chunks.append(".".join(current))
            current, count = [s], words
        else:
            current.append(s); count += words
    if current: chunks.append(".".join(current))
    return [c.strip() for c in chunks if c.strip()]

