def run_python(code: str) -> str:
    # In production: use a sandbox (e2b, modal, docker)
    allowed = ["import math", "import statistics", "from math", "from statistics"]
    first_line = code.split("\n")[0].strip()
    if first_line.startswith("import") and first_line not in allowed:
        return "Error: only math/statistics imports allowed"
    try:
        result = subprocess.run(["python3", "-c", code],
                                capture_output=True, text=True, timeout=5)
        return result.stdout or result.stderr
    except Exception as e:
        return str(e)

