# Dynamic batching simulation
class DynamicBatchServer:
    def __init__(self, model_fn, max_batch=32, wait_ms=5):
        self.model_fn  = model_fn
        self.max_batch = max_batch
        self.wait_ms   = wait_ms / 1000
        self.queue     = Queue()

    def infer(self, x) -> float:
        result_q = Queue()
        self.queue.put((x, result_q))
        return result_q.get(timeout=1.0)

    def _worker(self):
        while True:
            items = [self.queue.get()]
            deadline = time.time() + self.wait_ms
            while len(items) < self.max_batch and time.time() < deadline:
                try:    items.append(self.queue.get_nowait())
                except: time.sleep(0.0001)
            xs      = [x for x, _ in items]
            results = self.model_fn(xs)
            for (_, rq), r in zip(items, results):
                rq.put(r)

    def start(self):
        t = threading.Thread(target=self._worker, daemon=True)
        t.start()

