import threading
from collections import defaultdict
import numpy as np

class ParameterServer:
    def __init__(self, params: dict, lr=0.01):
        self.params = {k: v.copy() for k, v in params.items()}
        self.lr     = lr
        self.lock   = threading.Lock()
        self.step   = 0

    def pull(self):
        with self.lock:
            return {k: v.copy() for k, v in self.params.items()}

    def push(self, grads: dict):
        with self.lock:
            for k, g in grads.items():
                self.params[k] -= self.lr * g
            self.step += 1

np.random.seed(0)
ps     = ParameterServer({"w": np.array([0.0, 0.0, 0.0])}, lr=0.1)
losses = []

def worker_fn(worker_id):
