        w    = ps.pull()["w"]
        data = np.random.randn(3)
        grad = -2 * (1.0 - w @ data) * data  # gradient of (1 - w.data)^2
        ps.push({"w": grad})

threads = [threading.Thread(target=worker_fn, args=(i,)) for i in range(3)]
for t in threads: t.start()
for t in threads: t.join()
