from langchain.callbacks.base import BaseCallbackHandler
from langchain.schema import LLMResult
from datetime import datetime

class AuditCallbackHandler(BaseCallbackHandler):
    def __init__(self):
        self.events: list[dict] = []
        self._t0: float | None  = None

    def on_llm_start(self, serialized, prompts, **kwargs):
        self._t0 = datetime.utcnow().timestamp()
        self.events.append({"type": "llm_start", "prompts": prompts})

    def on_llm_end(self, response: LLMResult, **kwargs):
        dur    = datetime.utcnow().timestamp() - (self._t0 or 0)
        tokens = (response.llm_output or {}).get("token_usage", {}).get("total_tokens", 0)
        self.events.append({"type": "llm_end", "duration_s": round(dur, 3), "tokens": tokens})

    def on_tool_start(self, serialized, input_str, **kwargs):
        self.events.append({"type": "tool_start", "tool": serialized["name"], "input": input_str})

    def on_tool_end(self, output, **kwargs):
        self.events.append({"type": "tool_end", "output": str(output)[:200]})

    def summary(self) -> str:
        tokens = sum(e.get("tokens", 0) for e in self.events)
        tools  = sum(1 for e in self.events if e["type"] == "tool_start")
        return f"{len(self.events)} events | {tokens} tokens | {tools} tool calls"

