client = anthropic.Anthropic()

def stream_agent_response(user_message: str, tools: list[dict]):
    with client.messages.stream(
        model="claude-opus-4-7",
        max_tokens=1024,
        tools=tools,
        messages=[{"role": "user", "content": user_message}],
    ) as stream:
        current_tool = None
        tool_args    = ""

        for event in stream:
            if event.type == "content_block_delta":
                if event.delta.type == "text_delta":
                    print(event.delta.text, end="", flush=True)
                elif event.delta.type == "input_json_delta":
                    tool_args += event.delta.partial_json

            elif event.type == "content_block_start":
                if hasattr(event.content_block, "name"):
                    current_tool = event.content_block.name
                    print(f"\n[Tool: {current_tool}] ", end="", flush=True)

            elif event.type == "content_block_stop" and current_tool:
                print(f"args={tool_args[:80]}")
                current_tool = None
                tool_args    = ""

