from dataclasses import dataclass, field

@dataclass
class Span:
    name:     str
    start_ms: float
    end_ms:   float = 0.0
    meta:     dict  = field(default_factory=dict)

    @property
    def duration_ms(self): return self.end_ms - self.start_ms


class TracingCallbackHandler:
    def __init__(self):
        self.spans:   list[Span]           = []
        self.tokens:  defaultdict[str,int] = defaultdict(int)
        self._active: dict[str,float]      = {}

    def on_llm_start(self, serialized, prompts, run_id=None, **kw):
        self._active[str(run_id)] = time.time() * 1000

    def on_llm_end(self, response, run_id=None, **kw):
        start  = self._active.pop(str(run_id), time.time()*1000)
        t      = (response.llm_output or {}).get("token_usage",{}).get("total_tokens",0)
        self.tokens["llm"] += t
        self.spans.append(Span("llm", start, time.time()*1000, {"tokens": t}))

    def on_tool_start(self, serialized, tool_input, run_id=None, **kw):
        self._active[f"t_{run_id}"] = time.time() * 1000

    def on_tool_end(self, output, run_id=None, **kw):
        start = self._active.pop(f"t_{run_id}", time.time()*1000)
        self.spans.append(Span("tool", start, time.time()*1000))

    def report(self) -> dict:
        llm_spans = [s for s in self.spans if s.name == "llm"]
        return {
            "total_spans":  len(self.spans),
            "total_tokens": self.tokens["llm"],
            "avg_llm_ms":   sum(s.duration_ms for s in llm_spans) / max(1, len(llm_spans)),
        }

from datetime import datetime

class AgentMemory:
    """Simple episodic memory with semantic retrieval."""

    def __init__(self, embed_fn, similarity_fn, top_k=5):
        self.embed_fn     = embed_fn      # text -> vector
        self.similarity_fn = similarity_fn # (vec, [vec]) -> [float]
        self.episodes     = []            # list of {text, vector, ts}
        self.top_k        = top_k

    def remember(self, text: str):
        self.episodes.append({
            "text":   text,
            "vector": self.embed_fn(text),
            "ts":     datetime.now().isoformat(),
        })

    def recall(self, query: str) -> list[str]:
        if not self.episodes:
            return []
        q_vec = self.embed_fn(query)
        scores = self.similarity_fn(q_vec, [e["vector"] for e in self.episodes])
        ranked = sorted(zip(scores, self.episodes), key=lambda x: x[0], reverse=True)
        return [ep["text"] for _, ep in ranked[:self.top_k]]

    def inject_into_prompt(self, query: str) -> str:
        memories = self.recall(query)
        if not memories:
            return ""
        lines = "\n".join(f"- {m}" for m in memories)
        return f"Relevant memories:\n{lines}\n"

from dataclasses import dataclass, field
from typing import Callable

@dataclass
class Message:
    sender: str
    recipient: str
    content: str
    metadata: dict = field(default_factory=dict)


class AgentNode:
    def __init__(self, name: str, system_prompt: str, llm: Callable, tools: dict = None):
        self.name          = name
        self.system_prompt = system_prompt
        self.llm           = llm
        self.tools         = tools or {}
        self.inbox: list[Message] = []

    def receive(self, msg: Message):
        self.inbox.append(msg)

    def run(self) -> list[Message]:
        context = self.system_prompt
        for msg in self.inbox:
            context += f"\n[from {msg.sender}]: {msg.content}"
        response = self.llm(context)
        self.inbox.clear()
        # Simple routing: agent names its next recipient in brackets [AgentName]
        outgoing = []
        for line in response.splitlines():
            if line.startswith("[") and "]:" in line:
                end   = line.index("]")
                to    = line[1:end]
                body  = line[end+2:].strip()
                outgoing.append(Message(self.name, to, body))
        return outgoing

import re
from functools import wraps

# Tool permission scoping decorator
def scoped_tool(allowed_prefixes: list[str]):
    """Restrict a file-system tool to specific path prefixes."""
    def decorator(fn):
        @wraps(fn)
        def wrapper(path: str, *args, **kwargs):
            if not any(path.startswith(p) for p in allowed_prefixes):
                raise PermissionError(
                    f"Access denied: {path!r} is outside allowed scope {allowed_prefixes}"
                )
            return fn(path, *args, **kwargs)
        return wrapper
    return decorator


@scoped_tool(allowed_prefixes=["/workspace/output/", "/tmp/agent/"])
def write_file(path: str, content: str):
    with open(path, "w") as f:
        f.write(content)


# Prompt injection detection
INJECTION_PATTERNS = [
    r"ignore (all |your )?(previous |prior )?instructions",
    r"you are now",
    r"disregard (the |your )?system prompt",
    r"act as (?!a helpful)",
]

def is_injection(text: str) -> bool:
    return any(re.search(p, text, re.IGNORECASE) for p in INJECTION_PATTERNS)


# Circuit breaker
class AgentCircuitBreaker:
    def __init__(self, max_steps=20, max_cost_usd=1.0):
        self.steps = 0
        self.cost  = 0.0
        self.max_steps = max_steps
        self.max_cost  = max_cost_usd

    def check(self, step_cost: float = 0.0):
        self.steps += 1
        self.cost  += step_cost
        if self.steps > self.max_steps:
            raise RuntimeError(f"Circuit breaker: exceeded {self.max_steps} steps")
        if self.cost > self.max_cost:
            raise RuntimeError(f"Circuit breaker: exceeded ${self.max_cost:.2f} cost")

from enum import Enum
from dataclasses import dataclass

class RiskLevel(Enum):
    LOW    = "low"     # fully autonomous
    MEDIUM = "medium"  # log and notify, proceed
    HIGH   = "high"    # block and wait for approval


@dataclass
class PlannedAction:
    description: str
    tool:        str
    arguments:   dict
    risk:        RiskLevel
    reversible:  bool


def classify_risk(action: PlannedAction) -> RiskLevel:
    """Simple rule-based risk classifier."""
    irreversible_tools = {"send_email", "delete_file", "submit_payment", "deploy"}
    if action.tool in irreversible_tools or not action.reversible:
        return RiskLevel.HIGH
    if "write" in action.tool or "update" in action.tool:
        return RiskLevel.MEDIUM
    return RiskLevel.LOW


def execute_with_hitl(actions: list[PlannedAction], approval_fn, notify_fn) -> list:
    """Execute a plan with human checkpoints based on risk."""
    results = []
    for action in actions:
        risk = classify_risk(action)

        if risk == RiskLevel.HIGH:
            approved = approval_fn(
                f"Approve: {action.description}\n"
                f"Tool: {action.tool}({action.arguments})"
            )
            if not approved:
                results.append({"action": action.tool, "status": "rejected"})
                continue

        elif risk == RiskLevel.MEDIUM:
            notify_fn(f"Proceeding with: {action.description}")

        results.append({"action": action.tool, "status": "executed"})
    return results
